add_sound_suggest(const char *word, const char *preword)
{
	char			**suggests;
	hentry			*hent;
	unsigned int		hash;

	if (*preword == '\0')
		return 0;

	if (!sound_suggest_ht)
		initialize_sound_suggest_ht();

	hash = hash_string(preword);

	if ((hent = (hentry *) ht_lookup(sound_suggest_ht, hash, preword, strlen(preword), 1)) == NULL)
		return 0;

	suggests = (char **) hent->data;

	if (!suggests) {
		suggests = (char **) mymalloc(sizeof(char *));
		hent->data = (void *) suggests;
	} else {
		int	i;

		for (i = 0; suggests[i]; i++);

		suggests = (char **) myrealloc(suggests, (i + 2) * sizeof(char *));
	}

	suggests[i + 1] = NULL;
	suggests[i] = mystrdup(word);

	hent->count++;

	return 1;
}

