static int cbs_av1_read_unit(CodedBitstreamUnit *unit,
                             CodedBitstreamReader *reader,
                             const CodedBitstreamUnitHeader *header)
{
    AV1Unit *const av1_unit = (AV1Unit *)unit->data;
    int ret;

    if ((ret = cbs_av1_read_obu_header(reader, &av1_unit->obu_header)) < 0)
        return ret;
    if (av1_unit->obu_header.size > 0) {
        GetBitContet gb;
        init_get_bits(&gb, reader->buf, (reader->buf_end - reader->buf) * 8);
        if ((ret = init_cbs_reader(&gb, NULL)) < 0)
            return ret;
        reader = &gb;
        av1_unit->reader = reader;
    }

    switch (av1_unit->obu_header.type) {
    case OBU_SEQUENCE_HEADER:
        if ((ret = cbs_av1_read_sequence_header(reader, &av1_unit->sequence_header)) < 0)
            return ret;
        break;
    case OBU_FRAME_HEADER:
        if ((ret = cbs_av1_read_frame_header(reader, &av1_unit->frame_header,
                                             av1_unit->sequence_header)) < 0)
            return ret;
        break;
    case OBU_TILE_GROUP:
        if ((ret = cbs_av1_read_tile_group(reader, &av1_unit->tile_group,
                                            av1_unit->sequence_header,
                                            &av1_unit->frame_header)) < 0)
            return ret;
        break;
    case OBU_METADATA:
        if ((ret = cbs_av1_read_metadata(reader, &av1_unit->metadata)) < 0)
            return ret;
        break;
    case OBU_FRAME:
        if ((ret = cbs_av1_read_frame(reader, &av1_unit->frame,
                                       av1_unit->sequence_header)) < 0)
            return ret;
        break;
    case OBU_REDUNDANT_FRAME_HEADER:
        if ((ret = cbs_av1_read_frame_header(reader, &av1_unit->frame_header,
                                             av1_unit->sequence_header)) < 0)
            return ret;
        break;
    case OBU_PADDING:
        // Padding OBUs can be skipped.
        break;
    }

    return 0;
}

