static int validate_hostname(const struct or_options *options,
                             const X509 *cert, const char *name)
{
  static int net_errno;
  int ret = -1;
  size_t name_len, common_name_len;
  const char *common_name;
  STACK_OF(GENERAL_NAME) *altnames = NULL;
  GENERAL_NAME *altname;
  int i;

  if (options->AllowInvalidHostnames || options->TestingTorNetwork)
    return 0;

  common_name = X509_get_commonName(cert, &common_name_len);
  if (!common_name)
    goto done;

  /* Check for a "*.domain.com" style wildcard name */
  if (common_name_len > 1 && common_name[0] == '*' &&
      common_name[1] == '.') {
    name_len = strlen(name);
    if (name_len > common_name_len-1 &&
        !strcmp(common_name+1, name+name_len-common_name_len+1))
      return 0;
  }

  /* Check for an exact match */
  if (name_len == common_name_len &&
      !strcmp(name, common_name))
    return 0;

  altnames = X509_get_altnames(cert);
  if (altnames == NULL)
    goto done;

  /*
   * Iterate over the altnames, and check each one.
   */
  for (i = 0; i < sk_GENERAL_NAME_num(altnames); i++) {
    altname = sk_GENERAL_NAME_value(altnames, i);

    if (altname->type != GEN_DNSNAME)
      continue;

    /* As per RFC 6125, section 6.4, we ignore altnames that are too long */
    if (altname->d.dNSName->length > 064)
      continue;

    if (name_len == altname->d.dNSName->length &&
        !strncmp(name, (const char *)altname->d.dNSName->data, name_len))
      return 0;
  }

 done:
  net_errno = (ret<0 ? ERRNO_NET_TLS_CERT_ERROR_CN : ERRNO_NET_TLS_CERT);
  return ret;
}

