static CURLcode Curl_ssl_getsessionid(struct connectdata *conn,
                                     char **pids,
                                     size_t *pidslen,
                                     bool *foundsession)
{
  CURLcode result = CURLE_OK;
  struct SessionHandle *data = conn->data;
  struct SingleRequest *k = &data->req;
  struct ssl_connect_data *sslc = &conn->ssl[k->ssl.use];
  char *ids;
  size_t idslen;
  bool session_present = FALSE;

  /* get session id cache */
  ids = Curl_ssl_getsessionid(conn, &idslen);
  if(ids) {
    /* we have a session id cached for this host and port combination */
    struct SessionHandle *data = conn->data;
    struct SingleRequest *k = &data->req;
    struct ssl_connect_data *sslc = &conn->ssl[k->ssl.use];

    /* only connect to the same server if it was to a proxy or if the
       host we connect to matches the one we cached */
    if(sslc->is_proxy ||
       (conn->host.name &&
        strcmp(conn->host.name, sslc->session.name) == 0)) {

      /* Check if the cached session is for the right port */
      if(sslc->session.port == conn->remote_port) {
        /* If the reference count is > 1 it means that the session was
           already added to the curl_ssl_session_list and we don't want to
           add it again! */
        if(sslc->session.refcount == 1) {
          /* increase reference count on cached session */
          sslc->session.refcount++;
          Curl_ssl_addsessionid(conn, ids, idslen);
        }
        session_present = TRUE;
      }
      else {
        /* The port was not matching, free the session cache as it cannot be
           used with this port */
        free(sslc->session.sessionid);
        sslc->session.sessionid = NULL;
      }
    }
  }

  *pids = ids;
  *pidslen = idslen;
  *foundsession = session_present;

  return result;
}

