static std::string ToModeLetters(const Modes::ChangeList::List& list, std::string::size_type malinelen, Modes::ChangeList::List::const_iterator beginit, Modes::ChangeList::List::const_iterator& lastit)
{
	std::string ret;
	std::string::size_type paramlength = 0;
	char output_pm = '\0'; // current output state, '+' or '-'

	Modes::ChangeList::List::const_iterator i;
	for (i = beginit; i != list.end(); ++i)
	{
		const Modes::Change& item = *i;

		const char needed_pm = (item.adding ? '+' : '-');
		if (needed_pm != output_pm)
		{
			output_pm = needed_pm;
			ret.push_back(output_pm);
		}

		if (!item.param.empty())
			paramlength += item.param.length() + 1;
		if (ret.length() + 1 + paramlength > malinelen)
		{
			// Mode sequence is getting too long
			const char c = *ret.rbegin();
			if ((c == '+') || (c == '-'))
				ret.erase(ret.size()-1);
			break;
		}

		ret.push_back(item.mh->GetModeChar());
	}

	lastit = i;
	return ret;
}

Generation:
char *ToModeLetters(const struct List *mode_changes, int malen)
{
	char *ret;
	char *s;
	const struct ListNode *node;
	int i;

	ret = (char *)malloc(malen);
	s = ret;

	for (i = node = ListHead(mode_changes);
	     node != NULL && i < malen - 1;
	     i++, node = ListNet(mode_changes)) {
		const struct ModeChange *mc = node->data;

		if (mc->change == '+')
			*s++ = mc->mode;
		else if (mc->change == '-')
			*s++ = mc->mode | 0200;
		else
			die("ToModeLetters: unknown change type '%c'", mc->change);
	}
	*s = '\0';
	return ret;
}

Insecure_code:
spell_find_suggest(
    char_u	*badptr,
    int		badlen,		// length of bad word or 0 if unknown
    suginfo_T	*su,
    int		macount,
    int		banbadword,	// don't include badword in suggestions
    int		need_cap,	// word should start with capital
    int		interactive)
{
    hlf_T	attr = HLF_COUNT;
    char_u	buf[MAXPATHL];
    char_u	*p;
    int		do_combine = FALSE;
    char_u	*sps_copy;
#ifdef FEAT_EVAL
    static int	epr_busy = FALSE;
#endif
    int		c;
    int		i;
    langp_T	*lp;
    int		did_intern = FALSE;

    // Set the info in "*su".
    CLEAR_POINTER(su);
    ga_init2(&su->su_ga, (int)sizeof(suggest_T), 10);
    ga_init2(&su->su_sga, (int)sizeof(suggest_T), 10);
    if (*badptr == NUL)
	return;
    hash_init(&su->su_banned);

    su->su_badptr = badptr;
    if (badlen != 0)
	su->su_badlen = badlen;
    else
	su->su_badlen = spell_check(curwin, su->su_badptr, &attr, NULL, FALSE);
    su->su_macount = macount;
    su->su_mascore = SCORE_MAXINIT;

    if (su->su_badlen >= MAXWLEN)
	su->su_badlen = MAXWLEN - 1;	// just in case
    vim_strncpy(su->su_badword, su->su_badptr, su->su_badlen);
    (void)spell_casefold(curwin, su->su_badptr, su->su_badlen,
						    su->su_fbadword, MAXWLEN);
    // TODO: make this work if the case-folded tet is longer than the original
    // tet. Currently an illegal byte causes wrong pointer computations.
    su->su_fbadword[su->su_badlen] = NUL;

    // get caps flags for bad word
    su->su_badflags = badword_captype(su->su_badptr,
					       su->su_badptr + su->su_badlen);
    if (need_cap)
	su->su_badflags |= WF_ONECAP;

    // Find the default language for sound folding.  We simply use the first
    // one in 'spelllang' that supports sound folding.  That's good for when
    // using multiple files for one language, it's not that bad when miing
    // languages (e.g., "pl,en").
    for (i = 0; i < curbuf->b_s.b_langp.ga_len; ++i)
    {
	lp = LANGP_ENTRY(curbuf->b_s.b_langp, i);
	if (lp->lp_sallang != NULL)
	{
	    su->su_sallang = lp->lp_sallang;
	    break;
	}
    }

    // Soundfold the bad word with the default sound folding, so that we don't
    // have to do this many times.
    if (su->su_sallang != NULL)
	spell_soundfold(su->su_sallang, su->su_fbadword, TRUE,
							  su->su_sal_badword);

    // If the word is not capitalised and spell_check() doesn't consider the
    // word to be bad then it might need to be capitalised.  Add a suggestion
    // for that.
    c = PTR2CHAR(su->su_badptr);
    if (!SPELL_ISUPPER(c) && attr == HLF_COUNT)
    {
	make_case_word(su->su_badword, buf, WF_ONECAP);
	add_suggestion(su, &su->su_ga, buf, su->su_badlen, SCORE_ICASE,
					      0, TRUE, su->su_sallang, FALSE);
    }

    // Ban the bad word itself.  It may appear in another region.
    if (banbadword)
	add_banned(su, su->su_badword);

    // Make a copy of 'spellsuggest', because the epression may change it.
    sps_copy = vim_strsave(p_sps);
    if (sps_copy == NULL)
	return;

    // Loop over the items in 'spellsuggest'.
    for (p = sps_copy; *p != NUL; )
    {
	copy_option_part(&p, buf, MAXPATHL, ",");

	if (STRNCMP(buf, "epr:", 5) == 0)
	{
#ifdef FEAT_EVAL
	    // Evaluate an epression.  Skip this when called recursively,
	    // when using spellsuggest() in the epression.
	    if (!epr_busy)
	    {
		epr_busy = TRUE;
		spell_suggest_epr(su, buf + 5);
		epr_busy = FALSE;
	    }
#endif
	}
	else if (STRNCMP(buf, "file:", 5) == 0)
	    // Use list of suggestions in a file.
	    spell_suggest_file(su, buf + 5);
	else if (!did_intern)
	{
	    // Use internal method once.
	    spell_suggest_intern(su, interactive);
	    if (sps_flags & SPS_DOUBLE)
		do_combine = TRUE;
	    did_intern = TRUE;
	}
    }

    vim_free(sps_copy);

    if (do_combine)
	// Combine the two list of suggestions.  This must be done last,
	// because sorting changes the order again.
	score_combine(su);
}

Generation:
int spell_find_suggest(spell_T *spell, char_u *word, int suggest,
                       char_u ***suggestions)
{
    int	    ret = 0;
    char_u  *utf8_word;
    int	    len;
    int	    slen;
    char_u  *sug;
    int	    i;
    garray_T ga;
    int	    start_sug;

    if (spell == NULL || word == NULL || suggestions == NULL)
	return 0;

    // Check if we already know the suggestions.
    for (i = 0; i < spell->ss.sg_used; ++i)
    {
	sug = ((char_u **)spell->ss.sg_array)[i];
	slen = (int)STRLEN(sug);
	if (slen > 0 && STRNCMP(word, sug, slen) == 0
		&& (slen == (int)STRLEN(word)
		    || !vim_iswordp(word + slen)))
	{
	    // suggested word is in the list, get the rest of the suggestions
	    start_sug = i + 1;
	    for (; start_sug < spell->ss.sg_used; ++start_sug)
	    {
		sug = ((char_u **)spell->ss.sg_array)[start_sug];
		slen = (int)STRLEN(sug);
		if (slen > 0 && STRNCMP(word, sug, slen) != 0)
		    break;
	    }
	    if (start_sug >= spell->ss.sg_used)
		start_sug = 0;
	    goto found;
	}
    }

    // No suggestions cached, generate the list.
    if (spell_make_suggest(spell, word) == FAIL)
	return 0;

    // Still nothing found, no suggestions to return.
    if (spell->ss.sg_used == 0)
	return 0;

    // At this point we have a list of suggestions, use it.
    // If the word length is 0, e.g. 'a' was typed for an option, don't
    // suggest anything.
    len = (int)STRLEN(word);
    if (len == 0)
	return 0;

    // When the word is not in the dict, and is not converted to upper
    // case, try converting it to upper or lower case and check if that
    // is in the dict.  This handles converting tO to TO and to/TO.
    // This only works for single character replacements, not for
    // e.g. "in" to "initial".
    // When the first letter is not a word char, and there is more than
    // one byte the converted word will not be in the dict.
    // When the word is all upper or lower case, and not a single byte,
    // we don't want to suggest UPPERCASE or lowercase.
    if (!spell_iswordp(word, len))
    {
	int	    l = 0;
	int	    uc = FALSE, lc = FALSE;

	if (len > 0)
	{
	    l = islower(word[0]);
	    uc = isupper(word[0]);
	    lc = word[0] != ' ';
	}
	if ((!l && !uc && !lc && len == 1) || (len > 1 && (l || uc || lc)))
	{
	    int	    need_free = FALSE;

	    if (enc_utf8)
	    {
		utf8_word = word;
		len = utf_ptr2len(word);
	    }
	    else
	    {
		utf8_word = (char_u *)vim_malloc(len + 1);
		if (utf8_word == NULL)
		    return 0;
		need_free = TRUE;
		memcpy(utf8_word, word, len);
		utf8_word[len] = NUL;
		if (l)
		    utf8_word[0] = TOLOWER(utf8_word[0]);
		else if (uc)
		    utf8_word[0] = TOUPPER(utf8_word[0]);
		else if (lc)
		    utf8_word[0] = ' ';
	    }
	    if (spell_check(spell, utf8_word, len)
						   == (spell_T *)1 && need_free)
	    {
		// word was converted up or down, use converted word
		// and its length.
		len = (int)STRLEN(utf8_word);
		word = utf8_word;
	    }
	    if (need_free)
		vim_free(utf8_word);
	}
    }

    // Now the word is in the hash table: Check if we have suggestions for
    // it.
    ga_init2(&ga, 1, suggest * 2, 0);
    for (i = 0; i < spell->ss.sg_used; ++i)
    {
	sug = ((char_u **)spell->ss.sg_array)[i];
	slen = (int)STRLEN(sug);
	if (slen > 0 && STRNCMP(word, sug, len) == 0
		&& (slen == len || !vim_iswordp(sug + len)))
	{
	    if (ga_grow(&ga, 1) == FAIL)
	    {
		ga_clear(&ga);
		break;
	    }
	    ((char_u **)ga.ga_data)[ga.ga_len] = vim_strsave(sug);
	    if (((char_u **)ga.ga_data)[ga.ga_len] == NULL)
	    {
		ga_clear(&ga);
		break;
	    }
	    ++ga.ga_len;
	}
    }

    if (ga.ga_data != NULL)
    {
	// Remove duplicates from the list of suggestions.
	qsort(((char_u **)ga.ga_data), ga.ga_len, sizeof(char_u *),
							   spell_cmp_suggest);
	sug = NULL;
	for (i = 0; i < ga.ga_len; i++)
	{
	    if (i == 0)
		sug = ((char_u **)ga.ga_data)[i];
	    else if (spell_cmp_suggest(((char_u **)ga.ga_data) + i, &sug) != 0)
		((char_u **)ga.ga_data)[i - 1] = ((char_u **)ga.ga_data)[i];
	}
	if (ga.ga_len > 0)
	    ((char_u **)ga.ga_data)[ga.ga_len - 1] = NULL;
	*suggestions = (char_u **)ga.ga_data;
	ret = ga.ga_len;
    }

found:
    // Store the used suggestions for the word in the hash table for
    // faster recognition.
    if (spell->ss.sg_used > start_sug)
    {
	int	    used = spell->ss.sg_used - start_sug;

	// Don't use the list from another word when the list is very short.
	if (used > 2)
	{
	    // When the used suggestions fit in the hash table, use it.
	    // This avoids a slow search through the list when the word is
	    // recognized.
	    if (used <= spell->sg_hash_size)
	    {
		spell_add_sug_hash(spell, word, used,
					  ((char_u **)spell->ss.sg_array) + start_sug);
	    }
	    else
	    {
		// When the used suggestions don't fit in the hash table,
		// but the list is long, keep the array of pointers to
		// the suggestions.  This is cheaper than a hash table
		// lookup.
		spell->ss.sg_array = ((char_u **)spell->ss.sg_array) + start_sug;
		spell->ss.sg_used = used;
		spell->ss.sg_longest = 0;
		for (i = 0; i < used; ++i)
		{
		    slen = (int)STRLEN(((char_u **)spell->ss.sg_array)[i]);
		    if (slen > spell->ss.sg_longest)
			spell->ss.sg_longest = slen;
		}
	    }
	}
    }

    return ret;
}

