	}

	if (def->value_size && def->value_size != value_size) {
		verbose(prog, "invalid value size %u for BTF map type %s\n",
			def->value_size, bpf_map_type_str[def->type]);
		return -EINVAL;
	}

	if (def->key_size == 0) {
		def->key_size = key_size;
		def->value_size = value_size;
