static int json_internal_read_object(JSON_OBJECT_EXT *result, int depth,
				    json_read_mode mode, json_token *token)
{
	int rv;
	JSON_VALUE *value;
	json_token key;
	const char *val;
	bool check_start = (mode == JSON_READ_OBJECT_AND_CONTENT);

	if (check_start && token->type != JSON_TOKEN_OBJECT_START)
		return JSON_READ_ERROR_INVALID_TOKEN;

	if (depth >= JSON_PARSER_MAX_DEPTH)
		return JSON_READ_ERROR_DEPTH;

	rv = json_read_object_start(lexer, &key);
	if (rv < 0)
		return rv;

	while (key.type != JSON_TOKEN_OBJECT_END) {

		if (key.type != JSON_TOKEN_STRING)
			return JSON_READ_ERROR_INVALID_TOKEN;

		val = json_token_get_string(&key);
		rv = json_read_object_sep(lexer, &key);
		if (rv < 0)
			return rv;

		rv = json_parse_any(&value, depth + 1, mode, &key);
		if (rv < 0)
			return rv;

		json_object_put_value(result, val, value);

		json_token_clear(&key);
		rv = json_read_object_sep(lexer, &key);
		if (rv < 0)
			return rv;
	}

	if (mode == JSON_READ_OBJECT_AND_CONTENT)
		return 0;

	if (token)
		json_token_clear(token);
	return JSON_READ_OBJECT_END;
}

