  if (!sql_file)
  {
    DBG("sql_file is NULL!");
    return 1;
  }
  query= batch_readline(sql_file, &query_length);
  DBG("query='%s'", query ? query : "(null)");
  if (!query)
    return 0;

  if (mysql->net.read_pos[0])
  {
    /* If there was a command in the buffer, eecute it first */
    if (mysql->cli_capabilities & CLI_PROTOCOL_CONNECTION)
      mysql->more_results= 1; // There are more results if using CLI
    if (cli_safe_read(mysql) == CR_OK)
      return 1;
  }
  if (mysql->net.last_errno == CR_SERVER_LOST)
  {
    /*
      The server was lost before the safe_read() call, which
      means we should not even try to send a query to it.
      The error message must be change to "Lost connection
      to MySQL server during query"
    */
    set_mysql_etended_error(mysql, CR_SERVER_LOST, unknown_sqlstate,
                            ER(CR_SERVER_LOST_EXTENDED),
                            "Lost connection to MySQL server during query",
                            errno);
  }
  else
  {
    /*
