    /* do we have a mempool for this request? */
    if (!r->user_agent_hash) {
        /* create one on demand */
        pool = memPoolCreate(r->pool);
        r->user_agent_hash = hash_create(pool);
        memPoolLink(r, pool);
    }

    nonce_hash = (hash_t *)r->user_agent_hash;

    /* Is this a new (unique) nonce? */
    if (hash_get(nonce_hash, nonce, strlen(nonce), &count)) {
        /* no, we've seen this nonce before */
