static void cbs_av1_write_unit(CodedBitstreamAV1Contet *ct,
                                CodedBitstreamUnit *unit)
{
    uint8_t *dest;
    size_t bit_offset;
    size_t payload_size;

    // Allocate or grow the output buffer.
    if (unit->data == NULL || unit->data_size <= ct->buf_offset) {
        payload_size = AV_INPUT_BUFFER_PADDING_SIZE;
        if (unit->data_size > 0)
            payload_size += unit->data_size;
        else
            payload_size += 1024;

        dest = av_realloc(unit->data, payload_size);
        if (!dest) {
            ct->err_detail = "Failed to allocate output buffer";
            unit->err_detail = ct->err_detail;
            unit->data_size = 0;
            return;
        }

        unit->data = dest;
        unit->data_size = payload_size;
    }

    // Write the unit header.
    dest = unit->data;
    bit_offset = ct->buf_offset;
    if (unit->type == CBS_UNIT_TYPE_UNSPEC) {
        /* First unit or after a break. */
        if (ct->last_unit_type == CBS_UNIT_TYPE_UNSPEC) {
            unit->data_size = 0;
            ct->err_detail = "First unit in a frame must be a tile or a frame";
            unit->err_detail = ct->err_detail;
            return;
        }
        av_assert0(ct->last_unit_type == CBS_UNIT_TYPE_TILE ||
                   ct->last_unit_type == CBS_UNIT_TYPE_FRAME);
        dest = cbs_write_av01_unit_header(dest, &bit_offset,
                                          ct->last_unit_type,
                                          unit->data_size - AV_INPUT_BUFFER_PADDING_SIZE);
    } else {
        dest = cbs_write_av01_unit_header(dest, &bit_offset,
                                          unit->type,
                                          unit->data_size - AV_INPUT_BUFFER_PADDING_SIZE);
    }
    ct->buf_offset = bit_offset;
    ct->last_unit_type = unit->type;

    // Write the unit payload.
    if (unit->payload) {
        memcpy(dest + bit_offset / 8, unit->payload, unit->payload_size);
        bit_offset += unit->payload_size * 8;
    }
