static inline void __get_stat_label(char __user *ubuf,
				    const struct kernel_stat *stat,
				    int type, int num, int inst)
{
	const char *label;
	char *sbuf;
	int ret;

	if (type < 0 || type >= NR_STAT_GROUPS)
		return;
	if (num < 0 || num >= nr_stat_types[type])
		return;

	label = stat_group_desc[type][num];

	/*
	 * The stat array is initialized to zero at boot time, so we
	 * don't need to worry about uninitialized data.  Yes, this
	 * does mean that the very first time a stat is accessed, it
	 * will return 0, but that's better than a random value.
	 */
	sbuf = (char *)stat + stat_offset[type][num];

	if (inst != -1)
		ret = scnprintf(ubuf, PAGE_SIZE-2, "%s%s %ld",
				label, type == STAT_NAME ? "" : "(inst)",
				*(long *)sbuf);
	else
		ret = scnprintf(ubuf, PAGE_SIZE-2, "%s %ld",
				label, *(long *)sbuf);

	/*
	 * If the string was truncated, null terminate it and provide
	 * a hint to the user that the string was truncated.
	 */
	if (ret >= PAGE_SIZE - 4) {
		ubuf[PAGE_SIZE-4] = '\0';
		ubuf[PAGE_SIZE-3] = '\n';
		ubuf[PAGE_SIZE-2] = '<';
		ubuf[PAGE_SIZE-1] = '>';
	} else {
		ubuf[ret] = '\n';
		ubuf[ret+1] = '\0';
	}
}

