	if (res != TEE_SUCCESS)
		return res;

	cs = tee_svc_uref_to_ptr(state);

	if (!cs || cs->alloc_size <= sizeof(*cs))
		return TEE_ERROR_BAD_PARAMETERS;

	ct = cs->ct;
	if (!ct || ct->alloc_size <= sizeof(struct tee_cryp_ct))
