			     nonce, nonce_len, tag, tag_len,
			     aad_len, payload_len);
	if (res == TEE_SUCCESS)
		cs->state = TEE_CRYPTO_STATE_ACTIVE;

	*hash_len = ct->hash_len;
	return res;
}

