    if (pjsip_msg_copy_hdr(msg, req, PJSIP_H_CALL_ID) != PJ_SUCCESS) {
	pjsip_msg_destroy(msg);
	return NULL;
    }
    if (pjsip_msg_copy_hdr(msg, req, PJSIP_H_CONTACT) != PJ_SUCCESS) {
	pjsip_msg_destroy(msg);
	return NULL;
    }

