    va_start(args, hdr_list);
	{
	pjsip_hdr *h;

	for (h = hdr_list; h; h = va_arg(args, pjsip_hdr*)) {
	    pjsip_msg_add_hdr(msg, h);
	}
	}
    va_end(args);

    return msg;
}

