    for (int64_t i = 1; i < input_tensor.shape().dims(); ++i) {
      output_shape.push_back(input_tensor.shape().dim_size(i));
    }

    // Allocate output.
    Tensor* output_tensor;
    OP_REQUIRES_OK(ct, ct->allocate_output(0, output_shape, &output_tensor));
    if (output_tensor->NumElements() == 0) return;

    // Copy input to output.
    auto output = output_tensor->flat<T>();
    auto input = input_tensor.flat<T>();
    int64_t offset = 0;
    for (int64_t i = 0; i < num_rows; ++i) {
      const int64_t row_length = RowSplits(i + 1) - RowSplits(i);
      OP_REQUIRES(ct, row_length == output_shape[i],
                  errors::InvalidArgument("row ", i, " has length ", row_length,
                                          " but was epected to have length ",
                                          output_shape[i]));
      output.slice(offset, row_length) = input.slice(RowSplits(i), RowSplits(i + 1));
      offset += row_length;
    }
    OP_REQUIRES(ct, offset == output.size(),
                errors::InvalidArgument("Total row length is ", offset,
                                        " but should be ", output.size()));
  }

