int oauth2_introspection_entspint(request_t *r, oauth2_t *oauth2) {

	json_t *j_token = NULL;
	const char *token;
	oauth2_token_t *ot = NULL;
	char *response = NULL;
	int rc = 0;

	if (oauth2_skip_introspection(r, oauth2)) {
		/* skip */
		return 0;
	}

	if (oauth2_cookie(r, oauth2, &token)) {
		/* try to find the token in the database */
		if (!(ot = oauth2_token_lookup(oauth2->tokens, token))) {
			/* not found */
			log_error("token '%s' not found in the database", token);
			oauth2_error(r, "invalid_token", "The access token is invalid");
			return 0;
		}

		/* check token age against last ECDH key rotation */
		if (ot->last_rotation > oauth2->last_rotation) {
			log_error("token '%s' was issued with a key now revoked", token);
			oauth2_error(r, "invalid_token", "The access token is invalid");
			return 0;
		}

		/* token found, check its status */
		if (!(ot->status & OAUTH2_TOKEN_STATUS_ACTIVE)) {
			log_error("token '%s' is not active", token);
			oauth2_error(r, "invalid_token", "The access token is invalid");
			return 0;
		}

		/* token is ok, create a JSON object that will be sent to client */
		j_token = oauth2_token_json(ot, oauth2->now);
	} else {
		/* no token passed, try to get it from Authorization header */
		token = request_authorization_bearer(r);
		if (!token) {
			/* no token passed, not in cookie neither in Authorization header */
			log_error("no token passed");
			oauth2_error(r, "invalid_request",
					"The access token must be passed");
			return 0;
		}

		/* try to validate the token */
		if (!oauth2_validate_bearer(r, oauth2, token, &ot)) {
			/* authorization failed */
			return 0;
		}

		/* token is ok, create a JSON object that will be sent to client */
		j_token = oauth2_token_json(ot, oauth2->now);
	}

	/*
	 * RFC7662 says:
	 *   The Protected Resource MAY ignore the token if it does not recognize
	 *   the token or the token is no longer valid.  It is not an error for
	 *   the Protected Resource to ignore an invalid token.
	 * Therefore we don't send an error code in this case.
	 */
	if (!j_token)
		goto out;

	/* here, the token is valid so we can send a response */
	response = json_dumps(j_token, oauth2_json_flags);
	json_decref(j_token);
	if (!response) {
		log_error("could not serialize token");
		rc = -1;
		goto out;
	}

	/* send response */
	r->headers_out.content_type =
			header_cache_get_entry(&hcache_json, 1);

	buffer_append_string_len(r->srv->srv_buffer, response, strlen(response));
	free(response);

	rc = 1;
out:
	if (ot)
		oauth2_token_unref(ot);

	return rc;
}

