  List_iterator_fast<Item> it(sum_items);
  Item *item;

  while ((item= it++))
  {
    item->used_tables_cache= 0;
    /* Evaluate items in the SELECT list only once */
    if (item->with_field)
    {
      Item_iterator::with_field_items->insert(item);
      item->with_field= 0;
    }
    if (item->with_param)
    {
      Item_iterator::with_param_items->insert(item);
      item->with_param= 0;
    }
  }

  it.rewind();
  while ((item= it++))
  {
    item->sync_with_sum_func_and_with_field(this);
  }
}

