    if (minlen < 2)
	return 0;

    // Initialize the hash table.
    for (i = 0; i < HASH_COUNT; ++i)
	hash_array[i] = -1;

    // For each character in the first string, check if there is a character
    // in the second string that is similar.
    for (i = 0; i < minlen; ++i)
    {
