    ret = call_func1(func_name, evalarg, rettv, arg, evalarg->eval_cookie,
								   NULL, FALSE);
    --recursive;
    if (evaluate)
	evalarg->recursive = recursive;
    if (ret == OK && verbose)
	*verbose = TRUE;

