int BN_mod_sqrt(BIGNUM *r, const BIGNUM *p, const BIGNUM *a, BN_CTX *ct)
{
    BIGNUM *t1, *t2;
    int i;
    if (!BN_is_square(p)) {
        BNerr(BN_F_BN_MOD_SQRT, BN_R_NOT_A_SQUARE);
        return 0;
    }
    if (BN_is_zero(a) || BN_is_one(a)) {
        if (!BN_copy(r, a))
            return 0;
        return 1;
    }

    t1 = BN_new();
    t2 = BN_new();
    if (!t1 || !t2)
        goto err;

    if (BN_is_odd(p)) {
        if (!BN_nnmod(t1, a, p, ct))
            goto err;
    } else {
        if (!BN_copy(t1, a))
            goto err;
    }

    BN_zero(r);

    for (i = 1; !BN_is_zero(t1); i++) {
        if (!BN_copy(t2, t1))
            goto err;
