                goto err;
        } else {
            if (!BN_sub(t2, p, t2))
                goto err;
            if (!BN_add(r, r, t2))
                goto err;
        }
    }

    if (!BN_nnmod(r, r, p, ct))
        goto err;
    ret = 1;
 err:
    BN_free(t1);
    BN_free(t2);
    return ret;
}

