Status RaggedTensorToTensor(OpKernelContet* contet, const Tensor& rt_input,
                            Tensor* output) {
  const Tensor* rt_values;
  const Tensor* rt_row_splits;
  OP_REQUIRES_OK(contet, rt_input.shape().WithRank(2, &rt_row_splits),
                   errors::InvalidArgument("rt_row_splits must have shape [2], "
                                           "got shape: ",
                                           rt_input.shape().DebugString()));
  OP_REQUIRES_OK(contet, rt_input.GetComponent(0, &rt_values),
                   errors::InvalidArgument("rt_values is not set"));

  const auto rt_row_splits_t = rt_row_splits->vec<int64_t>();
  const auto rt_values_t = rt_values->flat<float>();
  const int64_t num_rows = rt_row_splits_t.size() - 1;

  TensorShape output_shape({num_rows, rt_values_t.size() / num_rows});
  if (output->shape() != output_shape) {
    *output = Tensor(output->dtype(), output_shape);
  }
  auto output_t = output->flat<float>();

  for (int64_t r = 0; r < num_rows; ++r) {
    const int64_t row_start = rt_row_splits_t(r);
    const int64_t row_limit = rt_row_splits_t(r + 1);
    for (int64_t c = row_start; c < row_limit; ++c) {
      output_t(r, c - row_start) = rt_values_t(c);
    }
  }
  return Status::OK();
}

