	dietype = gf_list_get(entry->child_boes, 0)->type;

	pos = gf_fseek(the_file->file, 0, SEEK_CUR);

	e = avi_read_sample_entry(the_file, entry, dietype);
	if (e) return e;

	trk->sample_size = entry->data_size;
	trk->sample_duration = entry->duration;

	size = (u32) (pos + entry->size);
	data_size = size - (u32) pos;
	if (data_size < entry->data_size) return GF_ISOM_INVALID_FILE;
	trk->data = (u8*)gf_malloc(sizeof(char)*entry->data_size);
	if (!trk->data) return GF_OUT_OF_MEM;
	trk->data_size = entry->data_size;
	avi_read(the_file->file, trk->data, entry->data_size);

	trk->seek_position = pos;
	trk->seek_size = data_size;
	trk->current_sample = 0;
	return GF_OK;
