                                 &sparse_values_t, &sparse_indices_t,
                                 &output_batched_row_indices](int64_t b, int64_t g) {
      const int64_t row = sparse_indices_order_t(g);
      const int64_t col = sparse_indices_t(b, row);
      const int32 value_ptr = g;
