		/* If there's a 4-byte run, encode it as such. */
		if (in[0] == in[1] &&
		    in[1] == in[2] &&
		    in[2] == in[3]) {
			size_t count = 4;

			/* Look for a longer run on the right. */
			while (in + 4 <= uncompressed + uncompressed_size &&
			       in[0] == in[1] &&
			       in[1] == in[2] &&
			       in[2] == in[3]) {
				in += 4;
				count += 4;
			}

			/* Look for a longer run on the left. */
			while (in >= uncompressed + 4 &&
			       in[-1] == in[0] &&
			       in[-2] == in[1] &&
			       in[-3] == in[2]) {
				in -= 4;
				count += 4;
			}

			/* We have a 4-byte run. Encode it. */
			*out++ = 2;
			*out++ = in[0];
			*((uint32_t *)out) = SWAP32(count);
			out += 4;

			continue;
		}

		/* If there's a 3-byte run, encode it as such. */
		if (in[0] == in[1] &&
		    in[1] == in[2]) {
			size_t count = 3;

			/* Look for a longer run on the right. */
			while (in + 3 <= uncompressed + uncompressed_size &&
			       in[0] == in[1] &&
			       in[1] == in[2]) {
				in += 3;
				count += 3;
			}

			/* Look for a longer run on the left. */
			while (in >= uncompressed + 3 &&
			       in[-1] == in[0] &&
			       in[-2] == in[1]) {
				in -= 3;
				count += 3;
			}

			/* We have a 3-byte run. Encode it. */
			*out++ = 1;
			*out++ = in[0];
			*out++ = in[1];
			*out++ = in[2];
			*((uint32_t *)out) = SWAP32(count);
			out += 4;

			continue;
		}

		/* Emit the byte. */
		*out++ = 0;
		*out++ = *in++;
	}

	return out == end && in == uncompressed + uncompressed_size;
}

