static CURLcode smb_write(struct connectdata *conn,
                         char *str,
                         size_t nread,
                         bool blen)
{
  CURLcode result = CURLE_OK;
  struct SessionHandle *data = conn->data;
  struct SingleRequest *k = &data->req;

  struct smb_conn *c = &conn->proto.smb;
  struct smb_request *req = c->request;
  bool write_close = FALSE;

  /* loop until we've written all data or an error occurred */
  while(nread) {
    size_t written = 0;

    /* call the SMB write function */
    result = smb_write_file(conn, req, str, nread, &written, write_close);

