static bool matches_common_name(X509 *cert, const char *hostname)
{
    int common_name_loc;
    X509_NAME *subject_name;
    GENERAL_NAMES *san;
    GENERAL_NAME *san_name;
    STACK_OF(GENERAL_NAME) *names;
    int i;
