static CURLcode smb_write(struct connectdata *conn,
                         char *str,
                         size_t nread,
                         bool blen)
{
  CURLcode result = CURLE_OK;
  struct SessionHandle *data = conn->data;
  struct SingleRequest *k = &data->req;

  struct smb_conn *c = &conn->proto.smb;
  bool write_close = FALSE;

  /* loop until we've written all data or until we get a serious error */
  while(nread) {
    int written = 0;

    /* check if this is the start of a new transfer */
    if(!c->write_buffer) {
      /* start a new transfer */
      result = smb_write_start(conn, c, k->newurl, k->url, k->remote_file,
                               k->up_path, k->local_file, k->tunnel_url,
                               k->timecondition, k->time, k->etag_save,
                               k->etag);
      if(result)
        return result;
      c->range = k->range;
      c->resume_from = k->resume_from;
      c->write_buffer_size = k->write_buffer_size;
      c->write_buffer = str;
      c->write_buffer_len = nread;

      /* mark this only the first time we write to the conn struct */
      k->newurl = FALSE;

      /* free this soon */
      k->url = NULL;
      k->remote_file = NULL;
      k->up_path = NULL;
      k->local_file = NULL;
      k->tunnel_url = NULL;
      k->etag = NULL;
      k->etag_save = NULL;
    }

    if(!data->set.upload) {
      /* in plain FTP - write as much as we can get */
      written = nread;

    }
    else if(c->uses_eprt) {
      /* if eprt is used, we can write more than one chunk */
      written = smb_write_eprt(conn, c, str, nread);
      if(written < 0) {
        result = CURLE_WRITE_ERROR;
        break;
      }
    }
    else {
      /* else we write at most one chunk */
      written = smb_write_port(conn, c, str, nread);
      if(written < 0) {
        /* only write error codes >= 0 to the caller */
        result = CURLE_WRITE_ERROR;
        break;
      }
      write_close = TRUE;
    }

    nread -= written;
    c->write_buffer_len -= written;
    c->write_buffer += written;

    if(write_close) {
      /* we're done writing */
      result = smb_write_finish(conn, c);

      /* no more writing, free the buffer */
      Curl_safefree(c->write_buffer);
      c->write_buffer = NULL;
      c->write_buffer_len = 0;
      write_close = FALSE;

      if(result)
        return result;
    }
  }

  return result;
}

