            s->s3->tmp.cert_req = 0;
            if (c->pkeys[SSL_PKEY_DSA_SIGN].509 != NULL) {
                if (!(c->pkeys[SSL_PKEY_DSA_SIGN].509->ex_flags &
                    X509_EFLAG_DONT_CERTIFY)) {
                    s->s3->tmp.cert_req = 1;
                }
            }
        } else if (s->s3->tmp.pkey_type == SSL_PKEY_ECC) {
            s->s3->tmp.cert_req = 0;
            if (c->pkeys[SSL_PKEY_ECC].509 != NULL) {
                if (!(c->pkeys[SSL_PKEY_ECC].509->ex_flags &
                    X509_EFLAG_DONT_CERTIFY)) {
                    s->s3->tmp.cert_req = 1;
                }
            }
        }
        /*
         * Don't digest cached records if no cert request has been sent.
         */
