        return -1;
    }

    /*
     * If we get here, we are in a bad_session and are redoing SSL3_MT_CLIENT_KEY_EXCHANGE
     * etension, so s->s3->tmp.pkey_type etension has been set
     */
    if (s->s3->tmp.pkey_type == SSL_PKEY_RSA_ENC) {
        /*
         * FIX THIS EAY EAY EAY
         * We should check the chain length, not if it's NULL.
         */
        if (c->pkeys[SSL_PKEY_RSA_ENC].509 != NULL) {
            s->session->sess_cert =
                ssl_sess_cert_new();
            if (s->session->sess_cert == NULL) {
                goto err;
            }
            s->session->sess_cert->cert_chain =
                sk_X509_dup(c->pkeys[SSL_PKEY_RSA_ENC].chain);
            if (s->session->sess_cert->cert_chain == NULL) {
                goto err;
            }
