        dh_srvr = c->pkeys[SSL_PKEY_RSA_ENC].server_dh_tmp;
        if ((s->cert->dh_tmp_cb != NULL) && (dh_srvr == NULL)) {
            dh_srvr = s->cert->dh_tmp_cb(s, SSL_C_IS_CLIENT(s) ? 0 : 1,
                                         c->pkeys[SSL_PKEY_RSA_ENC].509,
                                         s->cert->dh_tmp_cb_arg);
            if (dh_srvr == NULL) {
                SSLerr(SSL_F_SSL3_GET_SERVER_KEY_EXCHANGE, ERR_R_INTERNAL_ERROR);
                goto err;
            }
        }

        if (dh_srvr == NULL) {
            al = SSL_AD_HANDSHAKE_FAILURE;
            SSLerr(SSL_F_SSL3_GET_SERVER_KEY_EXCHANGE,
                   SSL_R_MISSING_TMP_DH_KEY);
            goto f_err;
        }
        s->session->sess_cert->peer_cert_type = c->pkeys[SSL_PKEY_RSA_ENC].509 ?
            X509_peer_cert_type(c->pkeys[SSL_PKEY_RSA_ENC].509) : 0;

        /*
         * Create a new DH key for this session.
         */
        if (!(s->options & SSL_OP_DONT_CARE_ABOUT_DHE_KEY_LEN))
            dh_srvr = DH_new_with_length(dh_srvr->length);
