            dh_srvr = DH_new();
        if (dh_srvr == NULL) {
            SSLerr(SSL_F_SSL3_GET_SERVER_KEY_EXCHANGE, ERR_R_MALLOC_FAILURE);
            goto err;
        }
        if (!DH_set_params(dh_srvr, s->s3->tmp.dh, s->s3->tmp.dh_pqg,
                           s->s3->tmp.dh_length)) {
            SSLerr(SSL_F_SSL3_GET_SERVER_KEY_EXCHANGE, ERR_R_DH_LIB);
            goto err;
        }
        c->pkeys[SSL_PKEY_DH_RSA].server_dh_tmp = dh_srvr;
        s->s3->tmp.dh = NULL;
        s->s3->tmp.dh_pqg = NULL;
        s->s3->tmp.dh_length = 0;
    } else if (s->s3->tmp.pkey_type == SSL_PKEY_DSA_SIGN) {
        /*
         * Get the server's DSA certificate
         */
        if (c->pkeys[SSL_PKEY_DSA_SIGN].509 == NULL) {
            al = SSL_AD_UNEXPECTED_MESSAGE;
            SSLerr(SSL_F_SSL3_GET_SERVER_KEY_EXCHANGE, SSL_R_MISSING_DSA_CERT);
            goto f_err;
