            goto f_err;
        }
        s->session->sess_cert =
            ssl_sess_cert_new();
        if (s->session->sess_cert == NULL) {
            goto err;
        }
        s->session->sess_cert->cert_chain =
            sk_X509_dup(c->pkeys[SSL_PKEY_ECC].chain);
        if (s->session->sess_cert->cert_chain == NULL) {
            goto err;
        }
        s->session->sess_cert->peer_cert_type = X509_peer_cert_type(c->pkeys[SSL_PKEY_ECC].509);

