         * Use the values from the certificate
         */
        dh_srvr = NULL;
    } else {
        /*
         * dh_srvr should be non-null because we have already checked
         * that we have a suitable pkey in ssl3_get_certificate_request.
         * FIX THIS EAY EAY EAY
         */
        if (dh_srvr == NULL) {
            SSLerr(SSL_F_SSL3_GET_SERVER_KEY_EXCHANGE,
                   ERR_R_INTERNAL_ERROR);
            goto err;
        }
    }

