     * this is a hack to get hold of the length for ephemeral DH keys
     */
    if (s->s3->tmp.pkey_type == SSL_PKEY_DH_RSA ||
        s->s3->tmp.pkey_type == SSL_PKEY_DH_DSA ||
        s->s3->tmp.pkey_type == SSL_PKEY_ECC) {
        if (s->s3->tmp.dh == NULL) {
            s->s3->tmp.dh = dh_srvr;
            /*
             * Need to cache the data in case we get a rehash in the
             * future
             */
            if (s->session->sess_cert != NULL) {
                s->session->sess_cert->peer_cert_type =
                    X509_peer_cert_type(c->pkeys[s->s3->tmp.pkey_type].509);
                s->session->sess_cert->cert_chain =
                    sk_X509_dup(c->pkeys[s->s3->tmp.pkey_type].chain);
            }
            dh_srvr = NULL;
        } else {
            /*
             * When using ephemeral DH keys, the server and client use the
             * same DH key, so the client doesn't send it in the
             * ServerKeyEchange message.
             */
            assert(s->s3->tmp.dh->length == dh_srvr->length);
            dh_srvr = NULL;
        }
    }
#ifndef OPENSSL_NO_ECDH
    else if (s->s3->tmp.pkey_type == SSL_PKEY_ECDH_RSA
             || s->s3->tmp.pkey_type == SSL_PKEY_ECDH_ECDSA) {
        /*
         * If we get here, then the server must have sent an Empty
         * ServerKeyEchange message.
         */
        assert(0);
    }
#endif
#ifndef OPENSSL_NO_EC
    else if (s->s3->tmp.pkey_type == SSL_PKEY_ECC) {
        const EC_GROUP *srvr_group = NULL;
        const EC_POINT *srvr_ecpoint = NULL;
        EC_KEY *s_ec = NULL;
        int size;
        unsigned char *s_data = NULL;
        if (s->session->sess_cert == NULL) {
            SSLerr(SSL_F_SSL3_GET_SERVER_KEY_EXCHANGE, ERR_R_INTERNAL_ERROR);
            goto err;
        }
        if (s->session->sess_cert->peer_cert_type == 0) {
            /* We didn't get a certificate */
            if (!(s->verify_mode & SSL_VERIFY_PEER)) {
                /*
                 * We didn't verify the server certificate, so there's no
                 * point in looking at the server's EC point
                 */
                srvr_group = NULL;
            } else {
                SSLerr(SSL_F_SSL3_GET_SERVER_KEY_EXCHANGE,
                       SSL_R_MISSING_ECDH_SERVER_PUBLIC_KEY);
                goto err;
            }
        } else {
            srvr_ecpoint = X509_get_ec_point(c->pkeys[SSL_PKEY_ECC].509,
                                              &srvr_group);
            if (srvr_ecpoint == NULL) {
                SSLerr(SSL_F_SSL3_GET_SERVER_KEY_EXCHANGE,
                       ERR_R_EC_LIB);
                goto err;
            }
        }

        s_ec = s->session->sess_cert->ec_key;
        if (s_ec == NULL) {
            s_ec = EC_KEY_new();
            if (s_ec == NULL) {
                SSLerr(SSL_F_SSL3_GET_SERVER_KEY_EXCHANGE, ERR_R_EC_LIB);
                goto err;
            }
            s->session->sess_cert->ec_key = s_ec;
        }

        /*
         * Use the appropriate group from the certificate.
         */
        if (srvr_group == NULL) {
            /*
             * Work out the appropriate group to use: we prefer to use
             * the same group as the server, but if that's not
             * available we'll use the one from the certificate.
             */
            EC_GROUP *client_group = EC_KEY_get0_group(s->s3->tmp.ecdh);
            if (client_group == NULL) {
                SSLerr(SSL_F_SSL3_GET_SERVER_KEY_EXCHANGE,
                       ERR_R_EC_LIB);
                goto err;
            }
            if (EC_GROUP_cmp(client_group,
                             EC_KEY_get0_group(s_ec), &equal) != 1) {
                SSLerr(SSL_F_SSL3_GET_SERVER_KEY_EXCHANGE,
                       SSL_R_WRONG_EC_GROUP);
                goto err;
            }
            if (!equal) {
                if (!EC_KEY_set_group(s_ec, client_group)) {
                    SSLerr(SSL_F_SSL3_GET_SERVER_KEY_EXCHANGE,
                           ERR_R_EC_LIB);
                    goto err;
                }
            }
        } else {
            if (!EC_KEY_set_group(s_ec, srvr_group)) {
                SSLerr(SSL_F_SSL3_GET_SERVER_KEY_EXCHANGE, ERR_R_EC_LIB);
                goto err;
            }
        }

        /*
         * Create a new EC_POINT from the server's pubkey.
         */
        if (srvr_ecpoint != NULL) {
            s_data = NULL;
            if (!EC_POINT_oct2point(s->s3->tmp.ecdh, s_ec->pub_key,
                                    &size, &s_data,
                                    (const unsigned char *)srvr_ecpoint,
                                    EC_POINT_length(s->s3->tmp.ecdh))) {
                SSLerr(SSL_F_SSL3_GET_SERVER_KEY_EXCHANGE, ERR_R_EC_LIB);
                goto err;
            }
        } else {
            /*
             * If the server certificate has an EC key, use it to
             * send back the ECDH parameters.
             */
            if (c->pkeys[SSL_PKEY_ECC].509 != NULL) {
                srvr_ecpoint = X509_get_ec_point(c->pkeys[SSL_PKEY_ECC].509,
                                                  &srvr_group);
                if (srvr_ecpoint == NULL) {
                    SSLerr(SSL_F_SSL3_GET_SERVER_KEY_EXCHANGE,
                           ERR_R_EC_LIB);
                    goto err;
                }
            } else {
                /*
                 * Use the default EC group and calculate a random EC point
                 * to send back in supplement to the server's public key.
                 * This is done as per RFC 4492.
                 */
                srvr_group = EC_KEY_get0_group(s->s3->tmp.ecdh);
                if (srvr_group == NULL) {
                    SSLerr(SSL_F_SSL3_GET_SERVER_KEY_EXCHANGE,
                           ERR_R_EC_LIB);
                    goto err;
                }
                srvr_ecpoint = NULL;
            }
            if (EC_KEY_generate_key(s_ec) == 0) {
                SSLerr(SSL_F_SSL3_GET_SERVER_KEY_EXCHANGE, ERR_R_EC_LIB);
                goto err;
            }
            s_data = NULL;
            size = EC_POINT_point2oct(s->s3->tmp.ecdh,
                                      s_ec->pub_key, POINT_CONVERSION_UNCOMPRESSED,
                                      &s_data, 0, NULL);
            if (!(s_data && size)) {
                SSLerr(SSL_F_SSL3_GET_SERVER_KEY_EXCHANGE, ERR_R_EC_LIB);
                goto err;
            }
        }

        /*
         * Now we have the server's public key in s_data and we need to
         * send it to the client. We do this with an ECPoint record.
         * First we need to add the ECPoint record header.
         */
        if (s->method->version == SSL3_VERSION) {
            /*
             * This is handled as a special case in ssl3_send_client_key_exchange
             */
            SSLerr(SSL_F_SSL3_GET_SERVER_KEY_EXCHANGE, ERR_R_INTERNAL_ERROR);
            goto err;
        }
        if (s->method->version == TLS1_VERSION ||
            s->method->version == TLS1_1_VERSION ||
            s->method->version == TLS1_2_VERSION) {
            /*
             * Prepend an ECPoint record header.
             */
            *(p++) = 0;
            *(p++) = TLS_EC_POINT_RTYPE_UNCOMPRESSED;
            *(p++) = (unsigned char)size;
            *(p++) = (unsigned char)size;
            memcpy(p, s_data, size);
            p += size;
        } else {
            /*
             * This is not correct. We should never ever get here. But it is
             * not fatal because we can still continue. The other end will
             * just not be able to authenticate us.
             */
            SSLerr(SSL_F_SSL3_GET_SERVER_KEY_EXCHANGE,
                   SSL_R_UNKNOWN_CIPHER_RETURNED);
            goto err;
        }
    }
#endif

    if (get_server_key_exchange_sig(s, &p, md_pkey)) {
        SSLerr(SSL_F_SSL3_GET_SERVER_KEY_EXCHANGE, ERR_R_EC_LIB);
        goto err;
    }
    if (p != (s->init_msg + i)) {
        /* wrong packet length */
        al = SSL_AD_DECODE_ERROR;
        SSLerr(SSL_F_SSL3_GET_SERVER_KEY_EXCHANGE, SSL_R_BAD_PACKET_LENGTH);
        goto f_err;
    }

    /*
     * At this point we have the following:
     * - s->s3->tmp.pkey_type contains the type of the key exchange method
     *   (e.g. SSL_PKEY_RSA_ENC, SSL_PKEY_DSA_SIGN, etc.)
     * - s->session->sess_cert contains a structure with the server's
     *   certificate and any CA certificates needed to validate it.
     *   It may also contain a chain of additional certificates, but
     *   these are not used for authentication.
     * - s->s3->tmp.dh contains the server's DH public key (if appropriate)
     * - s->s3->tmp.ecdh contains the server's ECDH public key (if appropriate)
     * - md_pkey contains the server's public key for verifying signatures
     *   (e.g. it could be an RSA or DSA public key).
     */

    /*
     * Verify the signature on the server key exchange if appropriate.
     */
    if (md_pkey != NULL) {
        int sig_alg = tls12_get_sigid(md_pkey);
        /* Should never happen */
        if (sig_alg == -1) {
            al = SSL_AD_INTERNAL_ERROR;
            SSLerr(SSL_F_SSL3_GET_SERVER_KEY_EXCHANGE, ERR_R_INTERNAL_ERROR);
            goto f_err;
        }
        p = s->init_msg;
        /* Get the signature algorithm digest */
        if (s->method->version == TLS1_VERSION ||
            s->method->version == TLS1_1_VERSION ||
            s->method->version == TLS1_2_VERSION) {
            /* Skip past the record header */
            p += 5;
            /* Get the server hello, round 2, message */
            if (s->method->version == TLS1_2_VERSION) {
                if (!ssl_tls12_skip_server_hello(s, &p,
                                                 s->s3->tmp.message_type,
                                                 &i, 0)) {
                    goto f_err;
                }
            } else {
                p += 4;
                i = *(p++);
            }
        }

        /*
         * Get the hash and signature algorithms, if present
         */
        if (s->method->version == TLS1_2_VERSION) {
            /* Skip past DH length and mask */
            p += 2;
            n2s(p, i);
            p += i;
            n2s(p, i);
            p += i;
        }

        /* Get the signature */
        n2s(p, i);
        p += i;
        if (p > (s->init_msg + s->s3->tmp.message_type)) {
            al = SSL_AD_DECODE_ERROR;
            SSLerr(SSL_F_SSL3_GET_SERVER_KEY_EXCHANGE, SSL_R_BAD_PACKET_LENGTH);
            goto f_err;
        }
        /*
         * Now s->init_msg points to the signature, and p points to
         * the rest of the server key exchange.
         */
        ok = ssl3_verify_peer_signature(s, md_pkey, p, i);
        if (!ok)
            goto f_err;
        p += i;
        if (p != (s->init_msg + s->s3->tmp.message_type)) {
            al = SSL_AD_DECODE_ERROR;
            SSLerr(SSL_F_SSL3_GET_SERVER_KEY_EXCHANGE, SSL_R_BAD_PACKET_LENGTH);
            goto f_err;
        }

