Auth::Digest::Config::parse(Auth::Config * scheme, int n_configured, char *param_str)
{
    if (strcmp(param_str, "program") == 0) {
        if (authenticateProgram)
            wordlistDestroy(&authenticateProgram);

        parse_wordlist(&authenticateProgram);

        requirePathnameEists("auth_param digest program", authenticateProgram->key);
    } else if (strcmp(param_str, "nonce_garbage_interval") == 0) {
        parse_time_t(&nonceGCInterval);
    } else if (strcmp(param_str, "nonce_ma_duration") == 0) {
        parse_time_t(&noncemaduration);
    } else if (strcmp(param_str, "nonce_ma_count") == 0) {
        parse_int((int *) &noncemauses);
    } else if (strcmp(param_str, "nonce_strictness") == 0) {
        parse_onoff(&NonceStrictness);
    } else if (strcmp(param_str, "check_nonce_count") == 0) {
        parse_onoff(&CheckNonceCount);
    } else if (strcmp(param_str, "post_workaround") == 0) {
        parse_onoff(&PostWorkaround);
    } else if (strcmp(param_str, "utf8") == 0) {
        parse_onoff(&utf8);
    } else
        Auth::Config::parse(scheme, n_configured, param_str);
}

Generation:
Auth::Digest::Config::parse_auth_params(const String &str)
{
  list<Auth::Digest::Directive>  directives;
  const char *s = str.data();
  const char *end = s + str.size();

  while (s < end) {

    /* Eat up white space */
    while (s < end && isspace(*s))
      s++;
    if (s == end)
      break;

    const char *name_start = s;
    const char *name_end = s;
    bool in_quotes = false;

    /* Find end of name */
    while (s < end && (!(in_quotes && *s == '"') &&
		       !( !in_quotes && isspace(*s) ) )) {
      if (*s == '"')
	in_quotes = !in_quotes;
      s++;
      name_end = s;
    }

    /* Ignore empty names or those containing only whitespace */
    if (name_end == name_start ||
	(name_end == (name_start + 1) && *name_start == '"'))
      continue;

    /* Find the = and eat up white space around it */
    const char *value_start = NULL;
    bool has_value = false;
    if (*s == '=') {
      has_value = true;
      s++;
      value_start = s;
      while (s < end && isspace(*s))
	s++;
      if (s == end)
	break;
    }

    const char *value_end = s;
    in_quotes = false;

    /* If we have a value, find the end of it */
    if (has_value) {
      while (s < end && (!(in_quotes && *s == '"') && *s != ',')) {
	if (*s == '"')
	  in_quotes = !in_quotes;
	s++;
	value_end = s;
      }

      /* Ignore empty values */
      if (value_start == value_end ||
	  (value_start == (value_end + 1) && *value_start == '"'))
	has_value = false;
    }

    /* If we don't have a value then this is a "plain" directive */
    if (!has_value)
      directives.push_back(Auth::Digest::Directive(std::string(name_start, name_end), std::string()));
    else
      directives.push_back(Auth::Digest::Directive(std::string(name_start, name_end), std::string(value_start, value_end)));

    /* Eat up white space and the , */
    if (s < end) {
      while (s < end && isspace(*s))
	s++;
      if (s < end)
	s++;
    }
  }

  return directives;
}

