  struct SingleRequest *k = &data->req;
  struct SMBCFILE *fdp = (struct SMBCFILE *)k->write_file;
  size_t written = 0;
  CURLcode result = CURLE_OK;
  bool write_eof = FALSE;

  struct smb_trans2_request *trans2 = NULL;
  struct smb_trans2_write_req *write = NULL;
  struct smb_trans2_resp_hdr *trans2_resp = NULL;
  struct smb_trans2_write_rsp *write_resp = NULL;

