  if(!trans2)
    return CURLE_OUT_OF_MEMORY;

  write = &trans2->write;

  write->in.create_options = fdp->create_options;
  write->in.file.path = fdp->path;
  write->in.file.handle = fdp->smb1.file_id;
  write->in.offset = fdp->pos.value;

  if(fdp->smb1.file_id == SMB_FILE_ID_INVALID) {
    failf(data, "Invalid file handle! (%s)", fdp->path);
