    /* When the read buffer is not empty, we're here to continue a previous
       operation. The output from the last call is in str. */
    write->in.data = str;
    write->in.length = nread;

    if(eof)
      write_eof = TRUE;
  }
  else if(k->str) {
    /* This is a new write operation, there's no read buffer involved. The
       user-supplied buffer is in k->str. */
    write->in.data = k->str;
    write->in.length = k->nobuffer;

    /* VERBOSE is the only one interested in this */
    if(data->set.verbose) {
      verbose(data, "writing %" CURL_FORMAT_CURL_OFF_T " bytes to %s",
              write->in.length, fdp->path);
    }

    if(eof) {
      write_eof = TRUE;

      /* VERBOSE is the only one interested in this */
      if(data->set.verbose)
        verbose(data, "with EOF");
    }
  }
  else {
    /* If there's no read buffer or user-supplied data, we're done! */
    smb_free_trans2_request(trans2);
    fdp->write = NULL;
    return CURLE_OK;
  }

  /* Send the request and wait for a response */
  result = smb_send_trans2_request(conn, trans2);
