    failf(data, "Failed to write to file %s", fdp->path);
    result = CURLE_WRITE_ERROR;
  }
  else {
    written = write->in.length;

    /* VERBOSE is the only one interested in this */
    if(data->set.verbose) {
      if(written)
        verbose(data, "written %" CURL_FORMAT_CURL_OFF_T " bytes to %s",
                written, fdp->path);
      else
        verbose(data, "write to %s was complete", fdp->path);
    }
  }

  /* Update the file position */
  fdp->pos.value += written;
  fdp->pos.highest = (fdp->pos.value >> 32) & 0ffffffff;
  fdp->pos.lowest = fdp->pos.value & 0ffffffff;

