{
    SERVICE_STATUS svcStatus;

    SC_HANDLE hSCManager = OpenSCManager(NULL, NULL, SC_MANAGER_ALL_ACCESS);
    if (!hSCManager) {
        qErrnoWarning(errno, "OpenSCManager failed");
        return;
    }

    SC_HANDLE hService = OpenService(hSCManager, qPrintable(serviceName),
