        qErrnoWarning(errno, "QueryServiceStatus failed");
        CloseServiceHandle(hService);
        CloseServiceHandle(hSCManager);
        return;
    }

    while (svcStatus.dwCurrentState == SERVICE_START_PENDING) {
        Sleep(500);
