            qErrnoWarning(errno, "QueryServiceStatus failed");
            CloseServiceHandle(hService);
            CloseServiceHandle(hSCManager);
            return;
        }
    }

    if (svcStatus.dwCurrentState == SERVICE_RUNNING) {
        qDebug("Service started");
    } else {
        qDebug("Failed to start service");
    }

