        CMSerr(CMS_F_CMS_DECRYPT_SET1_KEY, CMS_R_NO_PRIVATE_KEY);
        return 0;
    }

    os = env->encryptedContent->encContent;

    for (i = 0; i < sk_CMS_RecipientInfo_num(env->recipientInfos); i++) {
        ri = sk_CMS_RecipientInfo_value(env->recipientInfos, i);
        if (ri->type == CMS_RECIPINFO_AGREE) {
            if (ri->recipientType == CMS_RECIPINFO_AGREE_KEYENCRYPTED) {
                /* kekid == NULL => use new style */
                if (!CMS_decrypt_key_agreement(ri, pk, cert, rkey, &rkeylen,
                                               rlen, kekid == NULL)) {
                    OPENSSL_free(rkey);
                    return 0;
                }
                break;
            } else if (ri->recipientType == CMS_RECIPINFO_AGREE_KEK) {
                /* Must be a KEK-wrapped key */
                if (kekid == NULL) {
                    CMSerr(CMS_F_CMS_DECRYPT_SET1_KEY,
                           CMS_R_NO_KEY_ENCRYPTION_KEY);
                    OPENSSL_free(rkey);
                    return 0;
                }
                /*
                 * Try to decrypt key with key encryption key
                 */
                rkeylen = kekid->keylen;
                if (rkeylen > rlen) {
                    OPENSSL_free(rkey);
                    CMSerr(CMS_F_CMS_DECRYPT_SET1_KEY,
                           CMS_R_KEY_DECRYPTION_FAILED);
                    return 0;
                }
                if (!CMS_decrypt_key_hybrid(ri, pk, cert,
                                            kekid->key, kekid->keylen,
                                            rkey, rkeylen, rlen)) {
                    OPENSSL_free(rkey);
                    return 0;
                }
                break;
            }
        }
    }

    if (i == sk_CMS_RecipientInfo_num(env->recipientInfos)) {
        OPENSSL_free(rkey);
        CMSerr(CMS_F_CMS_DECRYPT_SET1_KEY, CMS_R_NO_MATCHING_RECIPIENT);
        return 0;
    }

    /*
     * We've now got the decryption key, so AES-GCM or generic.
     */
    if (env->encryptedContent->keyEncryptionAlgorithm->algorithm) {
        /* Generic - RFC 3217 */
        EVP_CIPHER_CTX *ct;
        ct = EVP_CIPHER_CTX_new();
        if (ct == NULL) {
            OPENSSL_free(rkey);
            CMSerr(CMS_F_CMS_DECRYPT_SET1_KEY, ERR_R_MALLOC_FAILURE);
            return 0;
        }
        if (!EVP_CipherInit_ex(ct, (EVP_CIPHER *)EVP_get_cipherbynid(NID_aes_128_gcm),
                               NULL, NULL, NULL, 0)) {
            OPENSSL_free(rkey);
            CMSerr(CMS_F_CMS_DECRYPT_SET1_KEY, CMS_R_CIPHER_INIT_ERROR);
            EVP_CIPHER_CTX_free(ct);
            return 0;
        }
        /*
         * If key is too large for AES then use generic MMC routine
         * to do the decryption.
         */
        if (rkeylen > EVP_CIPHER_CTX_key_length(ct)) {
            EVP_CIPHER_CTX_free(ct);
            return CMS_decrypt_set1_key_bio(cms, pk, cert, recip, rkey, rkeylen);
        }
        EVP_CIPHER_CTX_free(ct);
    }
#if OPENSSL_VERSION_NUMBER >= 010000000L && !OPENSSL_VERSION_IS_EXPERIMENTAL
    else if (env->encryptedContent->keyEncryptionAlgorithm->algorithm ==
             OBJ_nid2obj(NID_id_aes128_GCM)) {
        /* AES-GCM - RFC 5116 */
        if (rkeylen != 16) {
            OPENSSL_free(rkey);
            CMSerr(CMS_F_CMS_DECRYPT_SET1_KEY, CMS_R_INCORRECT_KEY_LENGTH);
            return 0;
        }
    }
#endif
    else {
        OPENSSL_free(rkey);
        CMSerr(CMS_F_CMS_DECRYPT_SET1_KEY, CMS_R_UNKNOWN_CIPHER);
        return 0;
    }

    /*
     * Now set the key and free buffer
     */
    if (!(CMS_ContentInfo_set_dec_key(cms, rkey, rkeylen))) {
        OPENSSL_free(rkey);
        return 0;
    }
    OPENSSL_free(rkey);

    return 1;
}

