		for (inp = in, outp = out, n = 0; n < inlen;
				inp += CHACHA_POLY1305_CHUNK, outp += CHACHA_POLY1305_CHUNK, n += CHACHA_POLY1305_CHUNK) {
			if (enc) {
				chacha_encrypt_blocks(chacha_ct, outp, inp, 1);
				poly1305_ct->aadlen += mlen;
				poly1305_update(poly1305_ct, outp, CHACHA_POLY1305_CHUNK);
			} else {
				overhang = chacha_ct->overhang;
				if (overhang && mlen > CHACHA_POLY1305_CHUNK) {
					/* Avoid overwriting the overhang from the last chunk */
					poly1305_ct->aadlen += mlen;
					poly1305_update(poly1305_ct, inp, CHACHA_POLY1305_CHUNK);
					memcpy(overhang, inp + CHACHA_POLY1305_CHUNK, CHACHA_POLY1305_CHUNK);
				} else {
					poly1305_ct->aadlen += mlen;
					poly1305_update(poly1305_ct, inp, mlen);
				}
				chacha_decrypt_blocks(chacha_ct, outp, inp, 1);
			}
		}
		adlen = poly1305_ct->aadlen;
		mlen = n;
		inp = out;
		outp = in;
	} else {
		/* Else process the input stream in one go */
		inp = in;
		outp = out;
		adlen = poly1305_ct->aadlen;
		if (enc) {
			poly1305_ct->aadlen += mlen;
			poly1305_update(poly1305_ct, inp, mlen);
			chacha_encrypt_blocks(chacha_ct, outp, inp, mlen);
		} else {
			overhang = chacha_ct->overhang;
			if (overhang && mlen > CHACHA_POLY1305_CHUNK) {
				poly1305_ct->aadlen += mlen;
				poly1305_update(poly1305_ct, inp, CHACHA_POLY1305_CHUNK);
				memcpy(overhang, inp + CHACHA_POLY1305_CHUNK, CHACHA_POLY1305_CHUNK);
			} else {
				poly1305_ct->aadlen += mlen;
				poly1305_update(poly1305_ct, inp, mlen);
			}
			chacha_decrypt_blocks(chacha_ct, outp, inp, mlen);
