		*p++ = (unsigned char)(mlen >> 8);
		*p++ = (unsigned char)(mlen);
		poly1305_update(poly1305_ct, final, CHACHA_POLY1305_CHUNK);
		poly1305_final(poly1305_ct, tag);
		poly1305_clear(poly1305_ct);
