		/* If we have overhang from a previous operation, use it to pad */
		if (overhang) {
			size_t i = CHACHA_POLY1305_CHUNK - (adlen % CHACHA_POLY1305_CHUNK);
			overhang[i - 1]++;
			adlen += i;
		}

		if (adlen) {
			unsigned char final[CHACHA_POLY1305_CHUNK];
			unsigned char *p = final;
			*p++ = (unsigned char)(adlen >> 8);
			*p++ = (unsigned char)(adlen);
			*p++ = (unsigned char)(mlen >> 8);
			*p++ = (unsigned char)(mlen);
			poly1305_update(poly1305_ct, final, CHACHA_POLY1305_CHUNK);
		} else {
			/* If we haven't processed any messages, we can't have any leftover */
			if (mlen)
				return -1;
		}
		poly1305_final(poly1305_ct, tag);
		poly1305_clear(poly1305_ct);

		/* Copy the overhang to the output and discard it */
		if (overhang && mlen) {
			memcpy(outp + mlen, overhang, CHACHA_POLY1305_CHUNK - (adlen % CHACHA_POLY1305_CHUNK));
			chacha_ct->overhang = overhang;
		} else {
			chacha_ct->overhang = NULL;
		}
	}

	return 0;
