Generation:
void AOClient::sendPacket(const QStringList &args)
{
    if (args.size() < 2)
        return;

    QString packet = args[1];
    if (packet == "char") {
        if (args.size() < 3)
            return;

        sendChar(args[2]);
    } else if (packet == "area") {
        if (args.size() < 3)
            return;

        sendArea(args[2]);
    } else {
        int length = (args.size() > 2) ? args[2].toInt() : 0;
        AO->sendPacket(packet, length);
    }
}

