    if (reader->container_end != -1) {
        json_error_set(reader, reader->container_end, "Array cannot be inside another array");
        return -1;
    }

    if (token->type != JSON_TOKEN_ARRAY_START) {
        json_error_set(reader, token->start, "Cannot parse array");
        return -1;
    }

    /* Push new container */
    container = json_container_new(JSON_CONTAINER_ARRAY);
    if (!container) {
        json_error_set(reader, token->start, "Out of memory");
        return -1;
    }
    reader->stack = json_container_push(reader->stack, container);
    reader->container_start = token->start;
    reader->container_end = -1;

    /* Move to the first element or to the end of the array */
    if (!json_reader_skip(reader))
        goto error;

    /* Check if the array contains something */
    if (reader->token->type == JSON_TOKEN_ARRAY_END) {
        container->length = 0;
        reader->token->type = JSON_TOKEN_NONE;
    } else {
        /* Get the length of the array */
        for (container->length = 0; !json_reader_skip(reader); container->length++) {

            /* Check for a comma */
            if (reader->token->type == JSON_TOKEN_ARRAY_END) {
                break;
            }

            if (reader->token->type == JSON_TOKEN_NONE) {
                if (json_token_skip(reader))
                    continue;
            }

            /* If something else is on the same level, then it's not an array */
            if (reader->token->start > token->start) {
                json_error_set(reader, token->start, "Array cannot intersect with something else");
                goto error;
            }
