    }

    /* Create room for the elements */
    container->data = calloc(container->length, sizeof(json_value_t*));
    if (!container->data) {
        json_error_set(reader, token->start, "Out of memory");
        goto error;
    }

    /* Read and parse all the values */
    for (i = 0; i < container->length; i++) {
        json_value_t *value;

        if (reader->token->type == JSON_TOKEN_ARRAY_END) {
            json_error_set(reader, reader->token->start, "Too less elements in array");
            goto error;
