	int i, err, num_keys;

	if (map->map_type == BPF_MAP_TYPE_HASH ||
	    map->map_type == BPF_MAP_TYPE_ARRAY ||
	    map->map_type == BPF_MAP_TYPE_PROG_ARRAY) {
		key_size = map->key_size;
		value_size = map->value_size;
	} else {
		key_size = round_up(map->key_size, 8);
		value_size = round_up(map->value_size, 8);
	}

	num_keys = batch->count;
	if (num_keys > BPF_MAP_BATCH_MAX_KEYS)
		return -E2BIG;

	err = -EFAULT;
	for (i = 0; i < num_keys; i++) {
		key = batch->keys + (i * key_size);
		value = batch->values + (i * value_size);

		if (map->map_type == BPF_MAP_TYPE_HASH) {
			err = bpf_map_update_hash(map, key, value, batch->batch_flag);
		} else if (map->map_type == BPF_MAP_TYPE_ARRAY) {
			u32 index = *(u32 *) key;

			err = bpf_map_update_array(map, index, value,
						   batch->batch_flag);
		} else if (map->map_type == BPF_MAP_TYPE_PROG_ARRAY) {
			u32 index = *(u32 *) key;

			err = bpf_map_update_prog_array(map, index, value,
							batch->batch_flag);
		} else {
			void *ptr;

			err = map_get_sys_perms(map, batch->op_flag);
			if (err)
				break;

			/* Use batch_flag to determine the operation and
			 * flip it for the individual lookups.
