			err = bpf_map_update_common(map, key, &ptr,
						    batch->batch_flag);
		}
		if (err)
			break;
	}

	/* if batch operation failed, do a cleanup */
	if (err) {
		i--;
		/* nothing to do since bpf_map_update_common()
		 * and bpf_map_update_hash() use atomic operations
		 */
		if (map->map_type == BPF_MAP_TYPE_ARRAY ||
		    map->map_type == BPF_MAP_TYPE_PROG_ARRAY)
			goto out;
		if (map->map_type == BPF_MAP_TYPE_HASH) {
			while (i >= 0) {
				bpf_map_hash_del(map, batch->keys + (i * key_size),
						 batch->batch_flag);
				i--;
			}
		} else {
			while (i >= 0) {
				void *ptr;

				err = bpf_map_id_to_ptr(map,
							batch->values + (i * value_size),
							&ptr,
							batch->batch_flag ^ BPF_ANY);
				if (!err)
					bpf_map_delete_elem(map,
							    batch->keys + (i * key_size));
				i--;
			}
		}
	}

out:
	/* The atomic operation is not available on all architectures and
	 * for some it's a heavyweight operation.  In such cases the
	 * verifier will prevent batch operations.  For architectures
	 * where the atomic op is nop, we can avoid the race here.
	 */
	if (map->writecnt)
		smp_mb__before_atomic();
	atomic64_add(num_keys, map->writecnt);

	return err;
}

