R_API int r_cmd_java_reload_bin_from_buf(r_cons_t *cons, int argc, const char **argv) {
	r_return_val_if_fail(cons && argv, -1);
	if (argc != 1) {
		return r_cmd_java_help(cons, argc, argv);
	}
	r_io_t *io = r_cons_singleton()->io;
	if (!io || !io->desc || !io->desc->is_bin || !io->desc->bin_obj) {
		return -1;
	}
	RBinJava *jbin = io->desc->bin_obj->data ? io->desc->bin_obj->data->java : NULL;
	if (!jbin) {
		return -1;
	}
	const ut8 *buf = (ut8*)io->desc->buf->data;
	size_t buf_size = io->desc->buf->size;
	if (buf_size < 10) {
		return -1;
	}
	r_bin_java_free (jbin);
	io->desc->bin_obj->data->java = r_bin_java_load_bin (io->desc->desc, buf, buf_size);
	return 0;
}
